# Created: 2026-05-20

#!/usr/bin/env python3
"""prior_fix_lookup.py — read-only memory KG lookup for prior similar fixes.

Closes orchestkit#1895. Signal-fired pre-flight step that runs before
/ork:fix-issue diagnosis when:

  error_text extractable + signature parses to non-None

Mirrors the memory_writeback pattern from PR #1889 but READ-ONLY — no
writeback. Pure helpers live in `signature_lib.py`.

Three exit-0 "skip" paths (none are errors):
  - signal absent: signature not extractable from error_text
  - yg-mcp-core not importable (orchestkit is public, yg-mcp-core is HQ-private)
  - memory MCP unreachable

Tool stack (yg-mcp-core>=0.3.0):
  - mcp_core.client.probe("memory")
  - mcp_core.client.call_tool("memory", "search_nodes", {"query": <signature>})

Usage:
  prior_fix_lookup.py <session-dir>

  <session-dir> must contain:
    fix-issue-input.json   {error_text: str}

Outputs:
  <session-dir>/prior-fix-matches.md     Markdown table of top-3 matches
  <session-dir>/prior-fix-matches.json   handoff JSON (status + matches_count + signature)

Exit codes:
  0   success, auto-skip per signals, OR MCP/dep unreachable (WARN only)
  1   pre-flight failure (missing args, session dir / required files absent)
  2   memory MCP returned an error AFTER probe succeeded (real error)
"""

from __future__ import annotations

import argparse
import json
import os
import sys
from pathlib import Path
from typing import Any

# Make sibling module importable when run as a script.
sys.path.insert(0, str(Path(__file__).resolve().parent))
from signature_lib import (  # noqa: E402
    extract_matches,
    extract_signature,
    render_markdown,
)

# Override at test time via env var.
DEFAULT_MCP_SERVER = os.environ.get("ORK_MEMORY_MCP_SERVER", "memory")
MATCH_LIMIT = 3


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------


def _parse_args(argv: list[str] | None = None) -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Read-only memory KG lookup for prior similar fixes.",
    )
    parser.add_argument(
        "session_dir",
        type=Path,
        help="Session directory containing fix-issue-input.json.",
    )
    return parser.parse_args(argv)


# ---------------------------------------------------------------------------
# handoff JSON
# ---------------------------------------------------------------------------


def _write_handoff(handoff_path: Path, payload: dict[str, Any]) -> None:
    handoff_path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _write_skip(handoff_path: Path, reason: str, signature: str | None = None) -> None:
    payload: dict[str, Any] = {"status": "skipped", "skip_reason": reason}
    if signature is not None:
        payload["signature"] = signature
    _write_handoff(handoff_path, payload)


# ---------------------------------------------------------------------------
# main
# ---------------------------------------------------------------------------


def main(argv: list[str] | None = None) -> int:
    args = _parse_args(argv)
    session_dir: Path = args.session_dir

    if not session_dir.is_dir():
        print(f"prior_fix_lookup: session dir not found: {session_dir}", file=sys.stderr)
        return 1

    input_path = session_dir / "fix-issue-input.json"
    handoff_path = session_dir / "prior-fix-matches.json"
    matches_md_path = session_dir / "prior-fix-matches.md"

    if not input_path.is_file():
        print(
            f"prior_fix_lookup: fix-issue-input.json missing at {input_path}",
            file=sys.stderr,
        )
        return 1

    try:
        payload = json.loads(input_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        print(f"prior_fix_lookup: cannot parse {input_path}: {exc}", file=sys.stderr)
        return 1

    error_text = payload.get("error_text")
    if not isinstance(error_text, str) or not error_text.strip():
        reason = "no error_text on fix-issue-input.json"
        print(f"prior_fix_lookup: auto-skipped — {reason}")
        _write_skip(handoff_path, f"signal absent: {reason}")
        return 0

    signature = extract_signature(error_text)
    if signature is None:
        reason = "signature extractor returned None"
        print(f"prior_fix_lookup: auto-skipped — {reason}")
        _write_skip(handoff_path, f"signal absent: {reason}")
        return 0

    print(f"prior_fix_lookup: signal fired — signature={signature!r}")

    # MCP preflight — fail-soft on dep miss OR unreachable server.
    try:
        from mcp_core.client import (
            McpToolError,
            McpUnreachable,
            call_tool,
            probe,
        )
    except ImportError:
        print(
            "prior_fix_lookup: WARN — yg-mcp-core not importable; skipping "
            "(install yg-mcp-core>=0.3.0 from pypi.yonyon.ai to enable)"
        )
        _write_skip(handoff_path, "yg-mcp-core not importable", signature=signature)
        return 0

    server = DEFAULT_MCP_SERVER
    if not probe(server):
        print(f"prior_fix_lookup: WARN — {server!r} MCP unreachable; skipping")
        _write_skip(handoff_path, f"{server!r} MCP unreachable", signature=signature)
        return 0

    print(f"prior_fix_lookup: searching {server!r} for nodes matching {signature!r}")
    try:
        result = call_tool(server, "search_nodes", {"query": signature})
    except (McpUnreachable, McpToolError) as exc:
        print(f"prior_fix_lookup: ERROR — {type(exc).__name__}: {exc}", file=sys.stderr)
        return 2

    matches = extract_matches(result, limit=MATCH_LIMIT)
    matches_md_path.write_text(render_markdown(matches, signature), encoding="utf-8")

    _write_handoff(
        handoff_path,
        {
            "status": "fired",
            "signature": signature,
            "matches_count": len(matches),
            "matches_md_path": str(matches_md_path),
            "server": server,
        },
    )
    print(f"prior_fix_lookup: ✓ wrote {matches_md_path} ({len(matches)} matches)")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
